// Extraction texte de la page job
const cheerio = require('cheerio');
const html = $input.item.json.data;
const $ = cheerio.load(html);

// Extraire titre, entreprise, description
const title = $('h1, .job-title, [class*="title"]').first().text().trim();
const company = $('[class*="company"], .company-name').first().text().trim();
const description = $('[class*="description"], .job-description, article').first().text().trim();

return {
  json: {
    job_title: title || 'Non trouvé',
    job_company: company || 'Non trouvé',
    job_description: description || $('body').text().substring(0, 5000),
    job_url: $('Form Trigger - Upload CV').item.json.job_url
  }
};

