// Validation et nettoyage JSON
const defaultAnalysis = {
  matching_score: 0,
  strengths: ['Analyse en cours...'],
  weaknesses: ['Analyse en cours...'],
  skills_match: { matched: [], missing: [] },
  experience_match: { level: 'unknown', years: 0, relevant: false },
  recommendation: 'Analyse non disponible',
  key_insights: [],
  interview_questions: []
};

try {
  let aiResponse = $input.item.json.ai_analysis;

  // Nettoyer markdown si présent
  if (typeof aiResponse === 'string') {
    aiResponse = aiResponse
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/i, '')
      .trim();

    aiResponse = JSON.parse(aiResponse);
  }

  // Valider champs obligatoires
  const requiredFields = ['matching_score', 'strengths', 'weaknesses', 'recommendation'];
  const missingFields = requiredFields.filter(f => !aiResponse.hasOwnProperty(f));

  if (missingFields.length > 0) {
    console.log('⚠️ Champs manquants:', missingFields.join(', '));
    throw new Error('Champs manquants: ' + missingFields.join(', '));
  }

  // Normaliser matching_score
  if (aiResponse.matching_score > 100) aiResponse.matching_score = 100;
  if (aiResponse.matching_score < 0) aiResponse.matching_score = 0;

  // Merge avec données originales
  return {
    json: {
      ...aiResponse,
      cv_text: $('Set - Merge CV + Job').item.json.cv_text.substring(0, 500) + '...',
      job_title: $('Set - Merge CV + Job').item.json.job_data.job_title,
      job_company: $('Set - Merge CV + Job').item.json.job_data.job_company,
      job_url: $('Set - Merge CV + Job').item.json.job_data.job_url,
      user_email: $('Set - Merge CV + Job').item.json.user_email,
      analyzed_at: new Date().toISOString(),
      validation_status: 'success'
    }
  };

} catch (error) {
  console.log('❌ Erreur validation JSON:', error.message);

  return {
    json: {
      ...defaultAnalysis,
      cv_text: $('Set - Merge CV + Job').item.json.cv_text.substring(0, 500) + '...',
      job_title: $('Set - Merge CV + Job').item.json.job_data.job_title,
      job_company: $('Set - Merge CV + Job').item.json.job_data.job_company,
      job_url: $('Set - Merge CV + Job').item.json.job_data.job_url,
      user_email: $('Set - Merge CV + Job').item.json.user_email,
      analyzed_at: new Date().toISOString(),
      validation_status: 'fallback',
      validation_error: error.message
    }
  };
}
